import{_ as t,o as i,c as o,a2 as r}from"./chunks/framework.Cuq8tsM6.js";const f=JSON.parse('{"title":"Process & Amplification","description":"","frontmatter":{"title":"Process & Amplification"},"headers":[],"relativePath":"docs/fr/advertisers/sponsored-social/workflow.md","filePath":"docs/fr/advertisers/sponsored-social/workflow.md"}'),s={name:"docs/fr/advertisers/sponsored-social/workflow.md"};function a(n,e,l,d,p,u){return i(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="workflow-de-campagne" tabindex="-1">Workflow de Campagne <a class="header-anchor" href="#workflow-de-campagne" aria-label="Permalink to &quot;Workflow de Campagne&quot;">​</a></h1><p>Le processus est conçu pour respecter la ligne éditoriale du Distributeur tout en garantissant vos objectifs de performance.</p><hr class="my-6"><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2d6fd6;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">1</div><div><h3 class="mt-0 text-blue-200">Brief &amp; Sélection</h3><p>Via la plateforme getinside :</p><ul><li>Sélectionnez le Distributeur partenaire (affinité d&#39;audience).</li><li><strong>Envoyez votre brief :</strong> Angle créatif (ex: Unboxing), Assets visuels et Messages clés.</li></ul></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2d6fd6;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">2</div><div><h3 class="mt-0 text-blue-200">Création du contenu</h3><p>Deux options s&#39;offrent à vous (à définir lors du brief) :</p><div style="display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-top:10px;"><div style="background:var(--vp-c-bg-soft);padding:10px;border-radius:4px;"><strong>Option A (Fourni)</strong><br> Vous fournissez la vidéo/photo prête à poster. </div><div style="background:var(--vp-c-bg-soft);padding:10px;border-radius:4px;"><strong>Option B (Co-création)</strong><br> Le Distributeur (ou notre Studio) crée le contenu pour un rendu &quot;natif&quot;. </div></div></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#2d6fd6;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">3</div><div><h3 class="mt-0 text-blue-200">Publication (Partnership Ad)</h3><p>Le Distributeur publie le contenu sur son compte avec l&#39;étiquette obligatoire <strong>&quot;Partenariat Rémunéré&quot;</strong>.</p><p class="fs-2 text-grey-dk-000"><em>Note : Cette étape nous permet de récupérer l&#39;ID du post pour l&#39;amplification. Vous validez le post une fois en ligne via un lien.</em></p></div></div><div style="display:flex;gap:20px;margin-bottom:40px;"><div style="flex-shrink:0;width:40px;height:40px;background:#28a745;color:white;border-radius:50%;display:flex;align-items:center;justify-content:center;font-weight:bold;font-size:18px;">🚀</div><div><h3 class="mt-0 text-green-200">Amplification Média</h3><p>C&#39;est ici que la magie opère. Nous activons la campagne publicitaire (Ads) sur le post.</p><ul><li><strong>Visibilité :</strong> Le post apparaît dans le fil d&#39;une audience large (Lookalike).</li><li><strong>Performance :</strong> Le format &quot;Natif&quot; génère des CPA souvent plus bas.</li></ul></div></div>',7)])])}const g=t(s,[["render",a]]);export{f as __pageData,g as default};
